class Solution:
    def isCompleteTree(self, root):
        nodes = [(root, 1)]
        i = 0
        count = 0
        last = 0
        while i < len(nodes):
            node, idx = nodes[i]
            i += 1
            count += 1
            last = max(last, idx)
            if node.left:
                nodes.append((node.left, idx * 2))
            if node.right:
                nodes.append((node.right, idx * 2 + 1))
        return last == count

