from collections import deque
class Solution:
    def isCompleteTree(self, root):
        q = deque([root])
        seen_gap = False
        while q:
            node = q.popleft()
            if node is None:
                seen_gap = True
            else:
                if seen_gap:
                    return False
                q.append(node.left)
                q.append(node.right)
        return True

