var isCompleteTree = function(root) {
    const q = [root];
    let head = 0;
    let seenGap = false;
    while (head < q.length) {
        const node = q[head++];
        if (node === null) {
            seenGap = true;
        } else {
            if (seenGap) return false;
            q.push(node.left);
            q.push(node.right);
        }
    }
    return true;
};
